import urllib.request
from html.parser import HTMLParser

# ===== EDIT THIS: the PUBLIC channel @username, without the @ =====
CHANNEL = "telegram"
LIMIT = 20
# =================================================================

VOID = {"br", "img", "hr", "input", "meta", "link", "source", "wbr"}

class TgParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.messages = []
        self.cur_post = None
        self.cur_date = None
        self.text_parts = []
        self.capture_depth = 0

    def _flush(self):
        if self.cur_post is not None:
            post = self.cur_post
            mid = None
            if "/" in post:
                tail = post.rsplit("/", 1)[1]
                if tail.isdigit():
                    mid = int(tail)
            self.messages.append({
                "message_id": mid,
                "channel": post.rsplit("/", 1)[0] if "/" in post else post,
                "text": "".join(self.text_parts).strip(),
                "date": self.cur_date,
                "url": "https://t.me/" + post,
            })
        self.cur_post = None
        self.cur_date = None
        self.text_parts = []
        self.capture_depth = 0

    def handle_starttag(self, tag, attrs):
        a = dict(attrs)
        if "data-post" in a:
            self._flush()
            self.cur_post = a["data-post"]
        if tag == "time" and a.get("datetime"):
            self.cur_date = a["datetime"]
        if self.capture_depth > 0:
            if tag == "br":
                self.text_parts.append("\n")
            if tag not in VOID:
                self.capture_depth += 1
        elif "tgme_widget_message_text" in a.get("class", ""):
            self.capture_depth = 1

    def handle_startendtag(self, tag, attrs):
        self.handle_starttag(tag, attrs)

    def handle_endtag(self, tag):
        if self.capture_depth > 0:
            self.capture_depth -= 1

    def handle_data(self, data):
        if self.capture_depth > 0:
            self.text_parts.append(data)

url = "https://t.me/s/" + CHANNEL
req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0 (compatible; n8n/1.0)"})

try:
    with urllib.request.urlopen(req, timeout=20) as resp:
        page = resp.read().decode("utf-8", "replace")
except Exception as e:
    return [{"error": "fetch_failed", "detail": str(e), "channel": CHANNEL, "hint": "Runner blocked outbound network. Use the HTTP Request node variant instead."}]

p = TgParser()
p.feed(page)
p._flush()

msgs = [m for m in p.messages if m["text"]]
msgs = msgs[-LIMIT:][::-1]

if not msgs:
    return [{"warning": "no_messages_parsed", "channel": CHANNEL, "html_len": len(page), "hint": "Channel may be private/nonexistent or markup changed."}]

return msgs
